// ─── Custom SVG visuals (no system Chart component exists — flagged above) ─────

/** Interactive donut: arcs animate as the scrubbed month changes. */
function DonutChart({ values }: { values: number[] }): JSX.Element {
  const total = values.reduce((sum, v) => sum + v, 0)
  const size = 168
  const stroke = 26
  const r = (size - stroke) / 2
  const cx = size / 2
  const cy = size / 2
  const circumference = 2 * Math.PI * r

  let accumulated = 0
  const arcs = values.map((value, i) => {
    const fraction = total > 0 ? value / total : 0
    const len = fraction * circumference
    const arc = {
      key: TREATMENTS[i].key,
      colorVar: TREATMENTS[i].colorVar,
      dasharray: `${len} ${circumference - len}`,
      dashoffset: -accumulated
    }
    accumulated += len
    return arc
  })

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} role="img" aria-label="Impression distribution by treatment">
      <circle cx={cx} cy={cy} r={r} fill="none" stroke="var(--cn-bg-2)" strokeWidth={stroke} />
      {arcs.map(arc => (
        <circle
          key={arc.key}
          cx={cx}
          cy={cy}
          r={r}
          fill="none"
          stroke={`var(${arc.colorVar})`}
          strokeWidth={stroke}
          strokeDasharray={arc.dasharray}
          strokeDashoffset={arc.dashoffset}
          transform={`rotate(-90 ${cx} ${cy})`}
          style={{ transition: 'stroke-dasharray 320ms ease, stroke-dashoffset 320ms ease' }}
        />
      ))}
    </svg>
  )
}

/** Tiny trend sparkline for a metric card. */
function Sparkline({ points, colorVar }: { points: number[]; colorVar: string }): JSX.Element {
  const w = 116
  const h = 40
  const max = Math.max(...points)
  const min = Math.min(...points)
  const span = max - min || 1
  const coords = points.map((p, i) => {
    const x = (i / (points.length - 1)) * w
    const y = h - ((p - min) / span) * (h - 6) - 3
    return `${x.toFixed(1)},${y.toFixed(1)}`
  })
  return (
    <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} aria-hidden="true">
      <polyline
        points={coords.join(' ')}
        fill="none"
        stroke={`var(${colorVar})`}
        strokeWidth={2}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  )
}

/** Multi-series trend line for "Top 5 Splits" — representative, static. */
function TrendLineChart(): JSX.Element {
  const w = 1180
  const h = 240
  const padL = 36
  const padB = 28
  const plotW = w - padL
  const plotH = h - padB
  const yTicks = [100, 75, 50, 25, 0]

  const toPath = (points: number[]): string =>
    points
      .map((p, i) => {
        const x = padL + (i / (points.length - 1)) * plotW
        const y = ((100 - p) / 100) * plotH
        return `${i === 0 ? 'M' : 'L'} ${x.toFixed(1)} ${y.toFixed(1)}`
      })
      .join(' ')

  return (
    <svg width="100%" viewBox={`0 0 ${w} ${h}`} role="img" aria-label="Top 5 splits metric change over time" className="overflow-visible">
      {yTicks.map((tick, i) => {
        const y = (i / (yTicks.length - 1)) * plotH
        return (
          <g key={tick}>
            <line x1={padL} y1={y} x2={w} y2={y} stroke="var(--cn-border-3)" strokeWidth={1} />
            <text x={padL - 8} y={y + 4} textAnchor="end" fontSize={11} fill="var(--cn-text-3)">
              {tick}
            </text>
          </g>
        )
      })}
      {MONTHS.map((month, i) => {
        const x = padL + (i / (MONTHS.length - 1)) * plotW
        return (
          <text key={month} x={x} y={h - 8} textAnchor="middle" fontSize={11} fill="var(--cn-text-3)">
            {month}
          </text>
        )
      })}
      {TREND_SERIES.map(series => (
        <path
          key={series.treatment.key}
          d={toPath(series.points)}
          fill="none"
          stroke={`var(${series.treatment.colorVar})`}
          strokeWidth={2}
          strokeLinecap="round"
          strokeLinejoin="round"
        />
      ))}
    </svg>
  )
}

