function ImpressionDistributionPanel(): JSX.Element {
  const [monthIndex, setMonthIndex] = useState(IMPRESSIONS_BY_MONTH.length - 1)

  const current = IMPRESSIONS_BY_MONTH[monthIndex]
  const total = useMemo(() => current.reduce((sum, v) => sum + v, 0), [current])
  const month = MONTHS[monthIndex]

  return (
    <Card.Root size="md" interactive={false} style={{ width: 460 }}>
      <Card.Content>
        <Layout.Vertical gap="lg">
          <Layout.Vertical gap="xs">
            <Text variant="heading-small" as="h2" color="foreground-1">
              Impression distribution over time
            </Text>
            <div style={{ width: 240 }}>
              <Select
                label="Split"
                optional
                orientation="horizontal"
                size="sm"
                options={METRIC_OPTIONS}
                defaultValue="conversion"
                onChange={() => {}}
              />
            </div>
          </Layout.Vertical>

          {/* Donut + legend with live percentages */}
          <Layout.Horizontal gap="lg" align="center" justify="between">
            <div className="relative shrink-0">
              <DonutChart values={current} />
              <Layout.Vertical
                gap="none"
                align="center"
                justify="center"
                className="absolute inset-0 pointer-events-none"
              >
                <Text variant="caption-single-line-normal" color="foreground-3">
                  {month} 2021
                </Text>
                <Text variant="heading-subsection" as="span" color="foreground-1">
                  {total.toLocaleString()}K
                </Text>
                <Text variant="caption-single-line-normal" color="foreground-3">
                  impressions
                </Text>
              </Layout.Vertical>
            </div>

            <Layout.Vertical gap="xs" className="shrink-0">
              {TREATMENTS.map((t, i) => {
                const pct = total > 0 ? Math.round((current[i] / total) * 100) : 0
                return (
                  <Layout.Horizontal key={t.key} gap="xs" align="center">
                    <span
                      aria-hidden="true"
                      className="shrink-0 rounded-cn-1"
                      style={{ width: 10, height: 10, backgroundColor: `var(${t.colorVar})` }}
                    />
                    <Text variant="caption-single-line-normal" color="foreground-2" className="w-[88px]">
                      {t.label}
                    </Text>
                    <Text variant="caption-strong" color="foreground-1" className="w-[36px] text-right">
                      {pct}%
                    </Text>
                  </Layout.Horizontal>
                )
              })}
            </Layout.Vertical>
          </Layout.Horizontal>

          {/* The time scrubber */}
          <Layout.Vertical gap="2xs">
            <Slider
              aria-label="Scrub timeline"
              value={[monthIndex]}
              min={0}
              max={IMPRESSIONS_BY_MONTH.length - 1}
              step={1}
              caption="min-max"
              minLabel="Jan 2021"
              maxLabel="Dec 2021"
              onValueChange={([v]) => setMonthIndex(v)}
            />
            <Text variant="caption-single-line-normal" color="foreground-3" align="center">
              Drag to scrub time · showing {month} 2021
            </Text>
          </Layout.Vertical>
        </Layout.Vertical>
      </Card.Content>
    </Card.Root>
  )
}

function MetricCard({ data, selected }: { data: MetricCardData; selected?: boolean }): JSX.Element {
  const positive = data.delta >= 0
  const colorVar = positive ? '--cn-comp-data-viz-05-indigo' : '--cn-comp-data-viz-02-purple'
  return (
    <Card.Root size="sm" interactive={false} selected={selected} className="flex-1">
      <Card.Content>
        <Layout.Vertical gap="xs">
          <Text variant="caption-single-line-normal" color="foreground-2" truncate>
            {data.name}
          </Text>
          <Layout.Horizontal gap="sm" align="center" justify="between">
            <Layout.Horizontal gap="2xs" align="center">
              <IconV2 name={positive ? 'nav-arrow-up' : 'nav-arrow-down'} size="sm" />
              <Text variant="heading-section" as="span" color={positive ? 'success' : 'danger'}>
                {positive ? '+' : ''}
                {data.delta}
              </Text>
            </Layout.Horizontal>
            <Sparkline points={data.spark} colorVar={colorVar} />
          </Layout.Horizontal>
          <Layout.Vertical gap="3xs">
            <Text variant="caption-light" color="foreground-4">
              Impact lies between
            </Text>
            <Text variant="caption-single-line-normal" color="foreground-3">
              {data.lowImpact} and {data.highImpact}
            </Text>
          </Layout.Vertical>
        </Layout.Vertical>
      </Card.Content>
    </Card.Root>
  )
}

